import { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDocStore } from '../store/docStore';
import { useAuthStore } from '../store/authStore';
import { UploadCloud, BookOpen, Clock, AlertCircle, LogOut } from 'lucide-react';

export default function Dashboard() {
  const { documents, loading, error, fetchDocuments, uploadDocument } = useDocStore();
  const { user, logout } = useAuthStore();
  const navigate = useNavigate();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchDocuments();
  }, [fetchDocuments]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      try {
        setUploading(true);
        await uploadDocument(file);
      } catch (err) {
        // Error is handled in store, but we catch to stop uploading state
      } finally {
        setUploading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    } else if (file) {
      alert('Please select a PDF file.');
    }
  };

  const getStatusColor = (status: string) => {
    switch(status) {
      case 'processed': return 'text-green-400 bg-green-400/10 border-green-400/20';
      case 'processing': return 'text-yellow-400 bg-yellow-400/10 border-yellow-400/20';
      case 'error': return 'text-red-400 bg-red-400/10 border-red-400/20';
      default: return 'text-zinc-400 bg-zinc-400/10 border-zinc-400/20';
    }
  };

  return (
    <div className="min-h-screen bg-zinc-950 text-slate-200 p-8">
      <header className="mb-12 border-b border-zinc-800 pb-6 flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-serif mb-2 text-slate-100">Your Library</h1>
          <p className="text-zinc-400">Welcome back, {user?.username}</p>
        </div>
        <button 
          onClick={logout}
          className="flex items-center gap-2 text-zinc-400 hover:text-red-400 transition"
        >
          <LogOut size={18} /> Logout
        </button>
      </header>

      {error && (
        <div className="mb-8 p-4 bg-red-900/20 border border-red-800 rounded-lg flex items-center gap-3 text-red-200">
          <AlertCircle size={20} className="text-red-400" /> {error}
        </div>
      )}

      <main className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">

        {/* Upload Card */}
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="glass p-8 rounded-xl border-dashed border-2 border-zinc-700 hover:border-electric-blue hover:bg-electric-blue/5 transition cursor-pointer flex flex-col items-center justify-center text-center h-64 group"
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="application/pdf" 
            className="hidden" 
          />
          <UploadCloud size={48} className="text-zinc-500 group-hover:text-electric-blue mb-4 transition" />
          <h2 className="text-xl font-bold mb-2 group-hover:text-electric-blue transition">Upload Document</h2>
          <p className="text-zinc-400 text-sm">Drag & drop or click to select a PDF</p>
          {uploading && <p className="mt-4 text-electric-blue text-sm animate-pulse">Uploading...</p>}
        </div>

        {/* Loading State */}
        {loading && !uploading && documents.length === 0 && (
          <div className="p-8 flex items-center justify-center text-zinc-500">
            Loading documents...
          </div>
        )}

        {/* Document Cards */}
        {documents.map((doc) => (
          <div 
            key={doc.document_id}
            onClick={() => navigate(`/reader/${doc.document_id}`)}
            className="glass p-6 rounded-xl hover:border-electric-blue transition cursor-pointer flex flex-col h-64 relative group overflow-hidden"
          >
            <div className="flex-1">
              <BookOpen size={24} className="text-electric-blue mb-4" />
              <h2 className="text-xl font-bold mb-2 line-clamp-2 text-slate-200 group-hover:text-electric-blue transition">{doc.title}</h2>
            </div>

            <div className="mt-auto border-t border-zinc-800 pt-4 flex flex-col gap-2">
              <div className="flex justify-between items-center">
                <span className="text-zinc-500 text-xs flex items-center gap-1">
                  <Clock size={12} /> {new Date(doc.created_at).toLocaleDateString()}
                </span>
                <span className={`text-xs px-2 py-1 rounded-full border ${getStatusColor(doc.status)}`}>
                  {doc.status}
                </span>
              </div>
            </div>
          </div>
        ))}

      </main>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authApi } from '../api/auth';
import { useAuthStore } from '../store/authStore';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const setAuth = useAuthStore((state) => state.setAuth);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await authApi.login(email, password);
      setAuth(response);
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Invalid login credentials');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex h-screen w-full items-center justify-center bg-zinc-950">
      <div className="glass p-8 rounded-2xl w-full max-w-md text-center">
        <h1 className="text-3xl font-bold mb-2 text-slate-200 font-serif">Welcome</h1>
        <p className="text-zinc-400 mb-8">Sign in to Noetix RAG</p>

        {error && <div className="mb-4 text-red-400 text-sm p-3 bg-red-900/20 border border-red-800 rounded">{error}</div>}

        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          <input
            type="email"
            placeholder="Email Address"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:outline-none focus:border-electric-blue text-slate-200 transition"
          />
          <input
            type="password"
            placeholder="Password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:outline-none focus:border-electric-blue text-slate-200 transition"
          />
          <button
            type="submit"
            disabled={loading}
            className="mt-4 bg-electric-blue text-zinc-950 font-semibold py-3 px-4 rounded-lg w-full hover:bg-opacity-90 transition disabled:opacity-50"
          >
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>

        <p className="mt-6 text-zinc-500 text-sm">
          Don't have an account? <Link to="/register" className="text-electric-blue hover:underline">Register</Link>
        </p>
      </div>
    </div>
  );
}

import { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { MessageSquare, X, ArrowLeft, Loader2, Send } from 'lucide-react';
import { useDocStore } from '../store/docStore';
import { documentApi } from '../api/document';
import { Document } from '../types/document';
import { useChatStore } from '../store/chatStore';

export default function Reader() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [doc, setDoc] = useState<Document | null>(null);
  const [loadingDoc, setLoadingDoc] = useState(true);

  const { messages, loading: chatLoading, sendMessage, clearSession } = useChatStore();
  const [inputMsg, setInputMsg] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Clear chat session when opening a new reader
    clearSession();

    // Fetch individual document
    const fetchDoc = async () => {
      try {
        if (id) {
          const res = await documentApi.getById(id);
          setDoc(res.document);
        }
      } catch (err) {
        console.error("Failed to load document", err);
        // Optionally redirect back to dashboard
      } finally {
        setLoadingDoc(false);
      }
    };
    fetchDoc();
  }, [id, clearSession]);

  useEffect(() => {
    // Scroll chat to bottom
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputMsg.trim() || chatLoading) return;
    sendMessage(inputMsg.trim());
    setInputMsg('');
  };

  return (
    <div className="flex h-screen bg-zinc-950 text-slate-200 overflow-hidden relative">
      {/* Document Area */}
      <main className={`flex-1 transition-all duration-300 ${isChatOpen ? 'mr-96' : ''} p-8 overflow-y-auto flex flex-col`}>

        <header className="mb-8 flex items-center justify-between">
          <button 
            onClick={() => navigate('/dashboard')}
            className="flex items-center gap-2 text-zinc-400 hover:text-slate-200 transition"
          >
            <ArrowLeft size={20} /> Back to Library
          </button>
        </header>

        {loadingDoc ? (
          <div className="flex-1 flex items-center justify-center text-zinc-500 flex-col gap-4">
            <Loader2 className="animate-spin" size={32} />
            Loading Document...
          </div>
        ) : doc ? (
          <div className="max-w-4xl w-full mx-auto bg-zinc-900 border border-zinc-800 p-12 md:p-16 shadow-2xl min-h-[150vh] font-serif leading-relaxed text-lg text-zinc-300">
            <h1 className="text-4xl font-bold mb-8 text-slate-100">{doc.title}</h1>
            <div className="mb-8 text-sm text-zinc-500 font-sans border-b border-zinc-800 pb-4">
              Status: <span className="text-electric-blue">{doc.status.toUpperCase()}</span> | Pages: {doc.page_count}
            </div>
            <p className="mb-6">
              (Document Content Viewer placeholder). In a full implementation, this area would render the actual PDF pages using a library like `react-pdf` or similar canvas-based viewer.
            </p>
            <p className="mb-6">
              The multi-agent RAG backend has already processed this document (ID: {doc.document_id}) located at `{doc.file_path}`.
            </p>
          </div>
        ) : (
          <div className="flex-1 flex items-center justify-center text-red-400">
            Document not found.
          </div>
        )}
      </main>

      {/* Floating Chat Toggle (if closed) */}
      {!isChatOpen && (
        <button 
          onClick={() => setIsChatOpen(true)}
          className="absolute bottom-8 right-8 bg-electric-blue text-zinc-950 p-4 rounded-full shadow-lg hover:scale-105 transition-transform z-10"
        >
          <MessageSquare size={24} />
        </button>
      )}

      {/* Collapsible Sidebar Chat */}
      <aside className={`fixed right-0 top-0 h-full w-96 glass-panel transform transition-transform duration-300 flex flex-col z-20 ${isChatOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <header className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
          <h2 className="font-semibold text-electric-blue flex items-center gap-2">
            <MessageSquare size={18} /> AI Assistant
          </h2>
          <button onClick={() => setIsChatOpen(false)} className="text-zinc-400 hover:text-slate-200 transition">
            <X size={20} />
          </button>
        </header>

        <div className="flex-1 p-4 flex flex-col gap-4 overflow-y-auto">
          {messages.length === 0 && (
            <div className="text-center text-zinc-500 text-sm mt-10">
              Ask a question about this document. The AI will use RAG to find answers.
            </div>
          )}

          {messages.map((msg) => (
            <div 
              key={msg.id}
              className={`p-3 rounded-lg text-sm border ${
                msg.role === 'user' 
                  ? 'bg-electric-blue/10 text-electric-blue border-electric-blue/20 ml-8 self-end'
                  : 'bg-zinc-800/50 text-slate-300 border-zinc-700 mr-8 self-start'
              }`}
            >
              {msg.content}
            </div>
          ))}
          {chatLoading && (
            <div className="bg-zinc-800/50 text-slate-300 p-3 rounded-lg mr-8 border border-zinc-700 self-start flex items-center gap-2">
              <Loader2 size={14} className="animate-spin text-electric-blue" />
              <span className="text-xs text-zinc-400">Agents are thinking...</span>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="p-4 border-t border-zinc-800 bg-zinc-900/50">
          <form onSubmit={handleSend} className="relative flex items-center">
            <input 
              type="text" 
              value={inputMsg}
              onChange={(e) => setInputMsg(e.target.value)}
              placeholder="Ask a question..." 
              disabled={chatLoading}
              className="w-full bg-zinc-950 border border-zinc-700 rounded-lg py-3 pl-4 pr-12 text-sm focus:outline-none focus:border-electric-blue text-slate-200 disabled:opacity-50"
            />
            <button 
              type="submit" 
              disabled={!inputMsg.trim() || chatLoading}
              className="absolute right-2 p-2 text-zinc-400 hover:text-electric-blue transition disabled:opacity-50"
            >
              <Send size={18} />
            </button>
          </form>
        </div>
      </aside>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authApi } from '../api/auth';
import { useAuthStore } from '../store/authStore';

export default function Register() {
  const [email, setEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const setAuth = useAuthStore((state) => state.setAuth);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await authApi.register(email, username, password);
      // Backend might log us in immediately, or might just return user data.
      // Assuming it returns standard auth response as per API docs
      if (response.access_token) {
        setAuth({ access_token: response.access_token, token_type: response.token_type, user: response.user });
      }
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Failed to register account');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex h-screen w-full items-center justify-center bg-zinc-950">
      <div className="glass p-8 rounded-2xl w-full max-w-md text-center">
        <h1 className="text-3xl font-bold mb-2 text-slate-200 font-serif">Create Account</h1>
        <p className="text-zinc-400 mb-8">Join the Noetix RAG platform</p>

        {error && <div className="mb-4 text-red-400 text-sm p-3 bg-red-900/20 border border-red-800 rounded">{error}</div>}

        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          <input
            type="email"
            placeholder="Email Address"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:outline-none focus:border-electric-blue text-slate-200 transition"
          />
          <input
            type="text"
            placeholder="Username"
            required
            minLength={3}
            maxLength={50}
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:outline-none focus:border-electric-blue text-slate-200 transition"
          />
          <input
            type="password"
            placeholder="Password"
            required
            minLength={8}
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:outline-none focus:border-electric-blue text-slate-200 transition"
          />
          <button
            type="submit"
            disabled={loading}
            className="mt-4 bg-cyber-purple text-zinc-100 font-semibold py-3 px-4 rounded-lg w-full hover:bg-opacity-90 transition disabled:opacity-50 shadow-[0_0_15px_rgba(138,43,226,0.3)]"
          >
            {loading ? 'Creating...' : 'Register'}
          </button>
        </form>

        <p className="mt-6 text-zinc-500 text-sm">
          Already have an account? <Link to="/login" className="text-electric-blue hover:underline">Sign In</Link>
        </p>
      </div>
    </div>
  );
}

import { create } from 'zustand';
import { ChatMessage } from '../types/chat';
import { chatApi } from '../api/chat';

interface ChatState {
  messages: ChatMessage[];
  sessionId: string | null;
  loading: boolean;
  error: string | null;
  sendMessage: (message: string) => Promise<void>;
  clearSession: () => void;
}

export const useChatStore = create<ChatState>((set, get) => ({
  messages: [],
  sessionId: null,
  loading: false,
  error: null,

  sendMessage: async (content: string) => {
    const { sessionId, messages } = get();

    // Optimistic UI update
    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', content };
    set({ messages: [...messages, userMsg], loading: true, error: null });

    try {
      const response = await chatApi.sendMessage(content, sessionId);

      const aiMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'assistant', 
        content: response.response 
      };

      set({ 
        messages: [...get().messages, aiMsg], 
        sessionId: response.session_id || sessionId,
        loading: false 
      });
    } catch (err: any) {
      set({ error: err.response?.data?.detail || 'Failed to send message', loading: false });
    }
  },

  clearSession: () => {
    set({ messages: [], sessionId: null, error: null });
  }
}));

import { create } from 'zustand';
import { Document } from '../types/document';
import { documentApi } from '../api/document';

interface DocState {
  documents: Document[];
  loading: boolean;
  error: string | null;
  fetchDocuments: () => Promise<void>;
  uploadDocument: (file: File) => Promise<void>;
}

export const useDocStore = create<DocState>((set) => ({
  documents: [],
  loading: false,
  error: null,

  fetchDocuments: async () => {
    set({ loading: true, error: null });
    try {
      const response = await documentApi.getAll();
      set({ documents: response.documents, loading: false });
    } catch (err: any) {
      set({ error: err.response?.data?.detail || 'Failed to fetch documents', loading: false });
    }
  },

  uploadDocument: async (file: File) => {
    set({ loading: true, error: null });
    try {
      await documentApi.upload(file);
      // Re-fetch documents after successful upload
      const response = await documentApi.getAll();
      set({ documents: response.documents, loading: false });
    } catch (err: any) {
      set({ error: err.response?.data?.detail || 'Failed to upload document', loading: false });
      throw err; // Re-throw to handle in component
    }
  }
}));
